// Récupère les données du webhook et l'archétype injecté par le Set node
const d = $input.first().json;
const body = d.body; // données envoyées par le frontend

// Calcul de l'âge (commence à 16 ans)
const age = 16 + (body.day || 1) - 1;

// Résumé du dernier chapitre
const lastContext = body.lastSummary
  ? `Dernier événement vécu : "${body.lastSummary}"`
  : `C'est le début de l'histoire. Le personnage vient de commencer sa vie adulte.`;

// Historique court des 3 derniers choix
const historyContext = (body.recentHistory && body.recentHistory.length > 0)
  ? `\nHistorique récent :\n${body.recentHistory.map(h => `- Jour ${h.day}: ${h.summary}`).join('\n')}`
  : '';

// Construction du prompt utilisateur (contexte de jeu)
const userPrompt = `CONTEXTE DU PERSONNAGE :
Nom : ${body.characterName || 'Inconnu'}
Ville : ${body.characterCity || 'Inconnue'}
Âge actuel : ${age} ans
Jour de vie : ${body.day || 1}
Chapitre du jour : ${(body.chaptersToday || 0) + 1}/3

STATS ACTUELLES (sur 100) :
- Santé    : ${Math.round(body.stats?.health    || 80)}/100
- Bonheur  : ${Math.round(body.stats?.happiness || 75)}/100
- Richesse : ${Math.round(body.stats?.wealth    || 40)}/100
- Moralité : ${Math.round(body.stats?.morality  || 70)}/100
- Karma    : ${((body.karma || 0.75) * 100).toFixed(0)}%

${lastContext}${historyContext}

Génère le chapitre ${(body.chaptersToday || 0) + 1} du jour ${body.day || 1} pour ${body.characterName || 'ce personnage'}.`;

// Payload final pour l'API Claude
return [{
  json: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1200,
    system: d.systemPrompt,
    messages: [{ role: 'user', content: userPrompt }]
  }
}];

const response = $input.first().json;

// n8n retourne { statusCode, headers, body } avec fullResponse: true
let responseBody = response.body;
if (typeof responseBody === 'string') {
  try { responseBody = JSON.parse(responseBody); } catch(e) {}
}

// Extrait le texte de la réponse Claude
const rawText = responseBody?.content?.[0]?.text || '';

// Nettoie les balises markdown si présentes
const clean = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

try {
  const parsed = JSON.parse(clean);

  // Validation basique de la structure
  if (!parsed.chapter || !Array.isArray(parsed.choices)) {
    throw new Error('Structure JSON invalide');
  }

  return [{ json: parsed }];

} catch(e) {
  // Fallback en cas d'erreur de parsing
  return [{ json: {
    chapter: "Les fils du destin s'emmêlent dans un silence inquiétant. Quelque chose dans l'espace entre les mondes résiste à être nommé...",
    choices: [
      { text: "Persévérer malgré l'obscurité",  karma_delta: 0,    hint: "Courage",     stat_effects: { health: 2,  happiness: -2, wealth: 0,  morality: 2  } },
      { text: "Attendre que la voie se dégage",  karma_delta: 0.02, hint: "Patience",    stat_effects: { health: 0,  happiness: -1, wealth: 0,  morality: 1  } },
      { text: "Se perdre dans l'incertitude",    karma_delta: -0.02, hint: "Résignation", stat_effects: { health: -3, happiness: -5, wealth: 0,  morality: -2 } }
    ]
  }}];
}

const body = $input.first().json.body;
const avatarNames = {
  angel:   "L'Ange Heureux",
  neutral: "Le Neutre",
  fallen:  "L'Ange Déchu",
  devil:   "Le Diable"
};
const avatarName = avatarNames[body.avatar] || 'une entité inconnue';
const health    = Math.round(body.stats?.health    || 0);
const happiness = Math.round(body.stats?.happiness || 0);
const karma     = ((body.karma || 0) * 100).toFixed(0);
const causeOfDeath = health <= 0
  ? 'son corps a rendu l\'âme'
  : 'son âme s\'est brisée sous le poids de la souffrance';

const prompt = `Écris une épitaphe poétique (3 phrases maximum, style sombre et beau, en français) pour ${body.characterName || 'un inconnu'}, ${body.age || 16} ans, de ${body.characterCity || 'nulle part'}.\n\nIl/elle a vécu ${body.day || 1} jours sous l'influence de ${avatarName}. Karma final : ${karma}%. Santé : ${health}/100. Bonheur : ${happiness}/100. Cause : ${causeOfDeath}.\n\nL'épitaphe doit refléter l'influence de ${avatarName} sur sa vie (lumineuse, froide, romantique sombre, ou damnée). Réponds UNIQUEMENT avec le texte de l'épitaphe, sans guillemets ni ponctuation d'encadrement.`;

return [{
  json: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 250,
    messages: [{ role: 'user', content: prompt }]
  }
}];

const response = $input.first().json;
let responseBody = response.body;
if (typeof responseBody === 'string') {
  try { responseBody = JSON.parse(responseBody); } catch(e) {}
}
const text = responseBody?.content?.[0]?.text || 'Une vie vécue. Une vie consumée. Le reste est silence.';
return [{ json: { epitaph: text.trim() } }];
